expression:
grel:if(
  isBlank(value),
  null,
  if(
    value.match(/.*,\s*(\d{4})-(\d{4})\.?\s*$/) != null,
    value.match(/.*,\s*(\d{4})-(\d{4})\.?\s*$/)[0].toNumber(),
    null
  )
)

